#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <iomanip>

// Base class
class Shape {
public:
    virtual double calculateArea() const {
        return 0;
    }
    virtual ~Shape() = default;
};

// Derived class Rectangle
class Rectangle : public Shape {
private:
    double width;
    double height;

public:
    Rectangle(double w, double h) : width(w), height(h) {}

    double calculateArea() const override {
        return width * height;
    }
};

// Derived class Circle
class Circle : public Shape {
private:
    double radius;

public:
    Circle(double r) : radius(r) {}

    double calculateArea() const override {
        return M_PI * radius * radius;
    }
};

int main() {
    std::stringstream ss;
    ss << std::fixed << std::setprecision(2);

    Shape* rect1 = new Rectangle(5, 10);
    Shape* circ1 = new Circle(3);
    Shape* rect_neg = new Rectangle(-2, 5); // Robustness test case
    Shape* circ2 = new Circle(1.5);

    ss << "Rectangle (5x10) Area: " << rect1->calculateArea() << std::endl;
    ss << "Circle (radius 3) Area: " << circ1->calculateArea() << std::endl;
    ss << "Rectangle (-2x5) Area: " << rect_neg->calculateArea() << std::endl;
    ss << "Circle (radius 1.5) Area: " << circ2->calculateArea() << std::endl;

    delete rect1;
    delete circ1;
    delete rect_neg;
    delete circ2;

    std::cout << ss.str();
    return 0;
}
